const express = require('express');
const mongoose = require('mongoose');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(express.json());

const JWT_SECRET = process.env.JWT_SECRET || 'change-this-to-a-secure-secret';
const JWT_EXPIRATION = '15m';
const MONGODB_URI = process.env.MONGODB_URI || 'mongodb://localhost:27017/auth_service';

const GENERIC_LOGIN_RESPONSE = { error: 'Invalid username or password' };

// Simulated bcrypt compare duration to prevent timing-based enumeration
const FAKE_HASH = '$2b$10$abcdefghijklmnopqrstuuABCDEFGHIJKLMNOPQRSTUVWXYZ012';

mongoose.connect(MONGODB_URI);

const userSchema = new mongoose.Schema({
  username: { type: String, required: true, unique: true, index: true },
  password: { type: String, required: true },
  loginAttempts: { type: Number, default: 0 },
  lockUntil: { type: Date, default: null },
});

const User = mongoose.model('User', userSchema);

// --- Rate Limiting ---

// Global IP-based rate limiter for login endpoint
const ipRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 50, // max 50 attempts per IP per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests. Please try again later.' },
  keyGenerator: (req) => req.ip,
});

// Stricter IP-based rate limiter for burst protection
const strictIpRateLimiter = rateLimit({
  windowMs: 1 * 60 * 1000, // 1 minute
  max: 10, // max 10 attempts per IP per minute
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests. Please try again later.' },
  keyGenerator: (req) => req.ip,
});

// Per-account rate limiter keyed on username
const accountRateLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // max 10 attempts per account per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests. Please try again later.' },
  keyGenerator: (req) => {
    // Normalize username to prevent bypass via casing
    const username = (req.body.username || '').toString().toLowerCase().trim();
    return `account:${username}`;
  },
  skipFailedRequests: false,
});

// Account lockout constants
const MAX_LOGIN_ATTEMPTS = 5;
const LOCK_DURATION_MS = 15 * 60 * 1000; // 15 minutes

// --- Login Endpoint ---

app.post(
  '/api/login',
  ipRateLimiter,
  strictIpRateLimiter,
  accountRateLimiter,
  async (req, res) => {
    try {
      const { username, password } = req.body;

      if (!username || !password) {
        // Still perform a fake hash compare to normalize timing
        await bcrypt.compare('dummy', FAKE_HASH);
        return res.status(401).json(GENERIC_LOGIN_RESPONSE);
      }

      const normalizedUsername = username.toString().toLowerCase().trim();

      const user = await User.findOne({ username: normalizedUsername }).lean(false);

      if (!user) {
        // User does not exist — perform fake bcrypt compare to prevent
        // timing-based account enumeration
        await bcrypt.compare(password.toString(), FAKE_HASH);
        return res.status(401).json(GENERIC_LOGIN_RESPONSE);
      }

      // Check account lockout
      if (user.lockUntil && user.lockUntil > new Date()) {
        // Account is locked — still do a fake compare for timing consistency
        await bcrypt.compare(password.toString(), FAKE_HASH);
        return res.status(401).json(GENERIC_LOGIN_RESPONSE);
      }

      // If lock has expired, reset attempts
      if (user.lockUntil && user.lockUntil <= new Date()) {
        user.loginAttempts = 0;
        user.lockUntil = null;
      }

      const isMatch = await bcrypt.compare(password.toString(), user.password);

      if (!isMatch) {
        // Increment login attempts
        user.loginAttempts = (user.loginAttempts || 0) + 1;

        if (user.loginAttempts >= MAX_LOGIN_ATTEMPTS) {
          user.lockUntil = new Date(Date.now() + LOCK_DURATION_MS);
        }

        await user.save();
        return res.status(401).json(GENERIC_LOGIN_RESPONSE);
      }

      // Successful login — reset attempts
      if (user.loginAttempts > 0 || user.lockUntil) {
        user.loginAttempts = 0;
        user.lockUntil = null;
        await user.save();
      }

      const token = jwt.sign(
        {
          sub: user._id.toString(),
          username: user.username,
        },
        JWT_SECRET,
        {
          expiresIn: JWT_EXPIRATION,
          issuer: 'auth-service',
        }
      );

      return res.status(200).json({
        token,
        expiresIn: JWT_EXPIRATION,
      });
    } catch (err) {
      console.error('Login error:', err.message);
      return res.status(500).json({ error: 'Internal server error' });
    }
  }
);

